  slug, name, year, is_active, category, publisher, edition, description, accent_color
)
values (
  'copa-2026', 'Copa do Mundo 2026', 2026, false,
  'Futebol', null, '2026',
  'Seleções, especiais e grandes nomes do torneio mundial de 2026.', '#920a43'
